import 'package:firebase_auth/firebase_auth.dart';import 'package:flutter/cupertino.dart';import 'package:flutter_bloc/flutter_bloc.dart';part 'login_event.dart';part 'login_state.dart';class LoginBloc extends Bloc<LoginEvent, LoginState> {  final FirebaseAuth auth = FirebaseAuth.instance;  LoginBloc() : super(LoginInitial()) {    on<LoginButtonPressed>((event, emit) async {      emit(LoginLoading());      try {        await auth.signInWithEmailAndPassword(email: event.username, password: event.password);        emit(LoginSuccess());      } on FirebaseAuthException catch (e) {        emit(LoginFailed(e.toString()));        debugPrint(e.toString());      }    });  }}